// src/services/api.js

import axios from "axios";

const API = axios.create({
  baseURL: "https://69f78e54dd0c226688edd079.mockapi.io/api/employees",
  timeout: 5000,
  headers: {
    "Content-Type": "application/json"
  }
});

// Optional: response interceptor for better error logging
API.interceptors.response.use(
  (response) => response,
  (error) => {
    console.error(
      "API Error:",
      error.response?.data || error.message
    );
    return Promise.reject(error);
  }
);

export default API;