<script setup>
import { ref, onMounted } from "vue";
import API from "./services/api";
import EmployeeForm from "./components/EmployeeForm.vue";
import EmployeeTable from "./components/EmployeeTable.vue";

const employees = ref([]);
const selectedEmployee = ref(null);

// Load all employees
const loadEmployees = async () => {
  try {
    const response = await API.get("/");
    employees.value = response.data;
  } catch (error) {
    console.error("Load error:", error.response?.data || error.message);
  }
};

// Add or Update employee
const saveEmployee = async (employeeData) => {
  try {
    if (selectedEmployee.value) {
      // FIX: remove extra /employees
      await API.put(`/${selectedEmployee.value.id}`, employeeData);
    } else {
      await API.post("/", employeeData);
    }

    await loadEmployees();
    selectedEmployee.value = null;

  } catch (error) {
    console.error("Save error:", error.response?.data || error.message);
  }
};

// Select employee for editing
const editEmployee = (employee) => {
  selectedEmployee.value = employee;
};

// Clear form
const clearForm = () => {
  selectedEmployee.value = null;
};

// Delete employee
const deleteEmployee = async (id) => {
  try {
    await API.delete(`/${id}`);
    await loadEmployees();
  } catch (error) {
    console.error("Delete error:", error.response?.data || error.message);
  }
};

onMounted(loadEmployees);
</script>

<template>
  <div class="container py-4">
    <h2 class="text-center mb-4">Employee Management System</h2>

    <EmployeeForm
      :employee="selectedEmployee"
      @save="saveEmployee"
      @clear="clearForm"
    />

    <EmployeeTable
      :employees="employees"
      @edit="editEmployee"
      @delete="deleteEmployee"
    />
  </div>
</template>