<script setup>
/* global defineProps, defineEmits */
import { reactive, watch } from "vue";

const props = defineProps({
  employee: {
    type: Object,
    default: null
  }
});

const emit = defineEmits(["save", "clear"]);

const emptyForm = () => ({
  employeeId: "",
  name: "",
  designation: "",
  department: "",
  salary: ""
});

const form = reactive(emptyForm());

watch(
  () => props.employee,
  (newValue) => {
    if (newValue) {
      form.employeeId = newValue.employeeId ?? "";
      form.name = newValue.name ?? "";
      form.designation = newValue.designation ?? "";
      form.department = newValue.department ?? "";
      form.salary = newValue.salary ?? "";
    } else {
      Object.assign(form, emptyForm());
    }
  },
  { immediate: true }
);

const submitForm = () => {
  emit("save", {
    ...form,
    salary: Number(form.salary)
  });
};

const resetForm = () => {
  Object.assign(form, emptyForm());
  emit("clear");
};
</script>

<template>
  <form class="card shadow-sm p-3 mb-4" @submit.prevent="submitForm">
    <h4 class="mb-3">{{ props.employee ? "Update Employee" : "Add Employee" }}</h4>

    <div class="row g-3">
      <div class="col-md-6">
        <input
          v-model="form.employeeId"
          class="form-control"
          placeholder="Employee ID"
          :disabled="!!props.employee"
        />
      </div>

      <div class="col-md-6">
        <input v-model="form.name" class="form-control" placeholder="Name" />
      </div>

      <div class="col-md-6">
        <input v-model="form.designation" class="form-control" placeholder="Designation" />
      </div>

      <div class="col-md-6">
        <input v-model="form.department" class="form-control" placeholder="Department" />
      </div>

      <div class="col-md-6">
        <input
          v-model.number="form.salary"
          type="number"
          class="form-control"
          placeholder="Salary"
        />
      </div>
    </div>

    <div class="mt-3">
      <button type="submit" class="btn btn-primary me-2">
        {{ props.employee ? "Update" : "Add" }}
      </button>
      <button type="button" class="btn btn-secondary" @click="resetForm">Clear</button>
    </div>
  </form>
</template>